<code class="code-line odd line-73">    Array<span class="token punctuation">.</span><span class="token function">Copy</span><span class="token punctuation">(</span>encResult<span class="token punctuation">,</span> encResult<span class="token punctuation">.</span>Length <span class="token operator">-</span> HashValue<span class="token punctuation">.</span>Length<span class="token punctuation">,</span> HashValue<span class="token punctuation">,</span> <span class="token number">0</span><span class="token punctuation">,</span> HashValue<span class="token punctuation">.</span>Length<span class="token punctuation">)</span><span class="token punctuation">;</span></code>
